css:
.orwellian-container {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100%;
  margin: 0;
  overflow: hidden;
  font-family: "Arial Black", "Helvetica Neue", Arial, sans-serif;
  font-weight: 900;
}
.orwellian-container .orwellian-loader {
  width: 280px;
  height: 280px;
  background-color: #000;
  border: 10px solid #333;
  position: relative;
  overflow: hidden;
  padding: 20px;
  box-sizing: border-box;
}

.orwellian-container .eye {
  width: 160px;
  height: 60px;
  background-color: #fff;
  border-radius: 50%;
  position: absolute;
  top: 30%;
  left: 50%;
  transform: translate(-50%, -60%);
  animation: pulse 2s infinite;
  overflow: hidden;
  z-index: 10;
}

.orwellian-container .pupil {
  width: 50px;
  height: 50px;
  background-color: #000;
  border-radius: 50%;
  position: absolute;
  top: 33%;
  left: 50%;
  transform: translate(-50%, -50%);
  animation: look-diagonal 4s infinite ease-in-out;
}

.orwellian-container .pupil::after {
  content: "";
  position: absolute;
  top: 50%;
  left: 50%;
  width: 30px;
  height: 30px;
  background: radial-gradient(circle, rgb(255, 0, 0) 0%, transparent 70%);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  opacity: 0.7;
}

.orwellian-container .eyelid {
  position: absolute;
  width: 100%;
  height: 100%;
  background-color: #000;
  animation: blink 4s infinite;
}

.orwellian-container .spotlight {
  position: absolute;
  top: 30%;
  left: 50%;
  width: 47px;
  height: 200px;
  background: linear-gradient(to bottom, rgba(255, 0, 0, 0.8), transparent);
  filter: blur(8px);
  transform-origin: top;
  animation: spotlight-sweep-diagonal 4s infinite ease-in-out;
}

.orwellian-container .text {
  position: absolute;
  bottom: 20px;
  left: 10px;
  right: 10px;
  text-align: center;
  font-size: 20px;
  font-weight: bold;
  color: #f8d17c;
  text-transform: uppercase;
  letter-spacing: 1px;
  animation: glitch 1s infinite;
  z-index: 20;
}

.orwellian-container .scan-lines {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    to bottom,
    transparent 50%,
    rgba(0, 0, 0, 0.3) 50%
  );
  background-size: 100% 4px;
  animation: scan 10s linear infinite;
  z-index: 30;
  opacity: 0.3;
  pointer-events: none;
}

.orwellian-container .tv-effect {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 50%, rgba(0, 0, 0, 0.25) 50%),
    linear-gradient(
      90deg,
      rgba(255, 0, 0, 0.06),
      rgba(0, 255, 0, 0.02),
      rgba(0, 0, 255, 0.06)
    );
  background-size: 100% 2px, 3px 100%;
  animation: tv-flicker 0.15s infinite;
  z-index: 35;
  pointer-events: none;
  opacity: 0.5;
}

.orwellian-container .orwellian-loader::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: repeating-linear-gradient(
    0deg,
    rgba(255, 255, 255, 0.03),
    rgba(255, 255, 255, 0.03) 1px,
    transparent 1px,
    transparent 2px
  );
  pointer-events: none;
  z-index: 40;
}

.orwellian-container .orwellian-loader::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(
    circle at center,
    transparent 30%,
    rgba(0, 0, 0, 0.5) 90%
  );
  z-index: 35;
  pointer-events: none;
}

@keyframes look-diagonal {
  0%,
  100% {
    transform: translateX(-50%) rotate(0deg);
  }
  25% {
    transform: translateX(-40%) rotate(-15deg);
  }
  75% {
    transform: translateX(-60%) rotate(15deg);
  }
}

@keyframes spotlight-sweep-diagonal {
  0%,
  100% {
    transform: translateX(-50%) rotate(0deg);
  }
  25% {
    transform: translateX(-40%) rotate(-15deg);
  }
  75% {
    transform: translateX(-60%) rotate(15deg);
  }
}

@keyframes pulse {
  0%,
  100% {
    transform: translate(-50%, -60%) scale(1);
  }
  50% {
    transform: translate(-50%, -60%) scale(1.05);
  }
}

@keyframes glitch {
  0%,
  100% {
    transform: translate(0, 0);
    opacity: 1;
  }
  25% {
    transform: translate(-2px, 2px);
    opacity: 0.75;
  }
  50% {
    transform: translate(2px, -2px);
    opacity: 0.5;
  }
  75% {
    transform: translate(-2px, -2px);
    opacity: 0.75;
  }
}

@keyframes blink {
  0%,
  90%,
  100% {
    height: 0;
  }
  95% {
    height: 100%;
  }
}

@keyframes scan {
  0% {
    background-position: 0 0;
  }
  100% {
    background-position: 0 100%;
  }
}

@keyframes tv-flicker {
  0% {
    opacity: 0.27049;
  }
  5% {
    opacity: 0.34801;
  }
  10% {
    opacity: 0.23175;
  }
  15% {
    opacity: 0.40923;
  }
  20% {
    opacity: 0.29481;
  }
  25% {
    opacity: 0.38584;
  }
  30% {
    opacity: 0.24928;
  }
  35% {
    opacity: 0.32451;
  }
  40% {
    opacity: 0.37031;
  }
  45% {
    opacity: 0.26941;
  }
  50% {
    opacity: 0.35755;
  }
  55% {
    opacity: 0.29288;
  }
  60% {
    opacity: 0.31821;
  }
  65% {
    opacity: 0.39726;
  }
  70% {
    opacity: 0.25294;
  }
  75% {
    opacity: 0.36898;
  }
  80% {
    opacity: 0.28995;
  }
  85% {
    opacity: 0.3398;
  }
  90% {
    opacity: 0.38703;
  }
  95% {
    opacity: 0.24619;
  }
  100% {
    opacity: 0.35762;
  }
}


.orwellian-container {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 300px; 
}


@media (max-width: 480px) {
  .orwellian-container .orwellian-loader {
    width: 240px;
    height: 240px;
  }

  .orwellian-container .eye {
    width: 140px;
    height: 50px;
  }

  .orwellian-container .pupil {
    width: 40px;
    height: 40px;
  }

  .orwellian-container .spotlight {
    width: 40px;
    height: 160px;
  }

  .orwellian-container .text {
    font-size: 16px;
  }
}


.orwellian-container .text {
  user-select: none; 
}

.orwellian-container .orwellian-loader:focus {
  outline: 2px solid #fff;
  outline-offset: 2px;
}

.orwellian-container .orwellian-loader {
  animation: subtle-rotate 6s infinite ease-in-out;
}


.orwellian-container .tv-effect::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(
      circle at center,
      rgba(255, 255, 255, 0.1) 0%,
      transparent 80%
    ),
    repeating-radial-gradient(
      circle at center,
      rgba(0, 0, 0, 0) 0,
      rgba(0, 0, 0, 0.1) 1px,
      transparent 1px,
      transparent 4px
    );
  background-size: 100% 100%, 3px 3px;
  pointer-events: none;
}


.orwellian-container .text {
  text-shadow: 0 0 5px rgba(255, 255, 255, 0.5),
    0 0 10px rgba(255, 255, 255, 0.3), 0 0 15px rgba(255, 255, 255, 0.2);
}


.orwellian-container .spotlight::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: radial-gradient(
    circle at top,
    rgba(255, 255, 255, 0.2) 0%,
    transparent 70%
  );
  filter: blur(5px);
}


@keyframes eye-glow {
  0%,
  100% {
    box-shadow: 0 0 10px rgba(255, 0, 0, 0.5);
  }
  50% {
    box-shadow: 0 0 20px rgba(255, 0, 0, 0.8);
  }
}

.orwellian-container .eye {
  animation: pulse 2s infinite, eye-glow 4s infinite;
}

.blocks {
  border: 2px solid #2b83e2;
  max-width: 158px;
  padding: 4px;
  border-radius: 8px;
  gap: 4px;
  display: flex;
  flex-wrap: wrap;
}
.blocks .block {
  display: flex;
  flex: 1;
  border-radius: 4px;
  background: #2b83e2;
  width: 75px;
  height: 75px;
  animation: blockLoading 1s infinite;
}
.blocks .block:nth-child(1) {
  animation-delay: 0ms;
}
.blocks .block:nth-child(2) {
  animation-delay: 200ms;
}
.blocks .block:nth-child(3) {
  animation-delay: 400ms;
}
.blocks .block:nth-child(4) {
  animation-delay: 600ms;
}
@keyframes blockLoading {
  0%,
  100% {
    flex: 1;
  }
  50% {
    flex: 4;
  }
}

.spinner {
  position: relative;
  width: 35.2px;
  height: 35.2px;
}

.spinner::before,
.spinner::after {
  content: '';
  width: 100%;
  height: 100%;
  display: block;
  animation: spinner-b4c8mmhg 0.5s backwards, spinner-49opz7hg 1.25s 0.5s infinite ease;
  border: 8.8px solid #000000;
  border-radius: 50%;
  box-shadow: 0 -52.8px 0 -8.8px #000000;
  position: absolute;
}

.spinner::after {
  animation-delay: 0s, 1.25s;
}

@keyframes spinner-b4c8mmhg {
  from {
    box-shadow: 0 0 0 -8.8px #000000;
  }
}

@keyframes spinner-49opz7hg {
  to {
    transform: rotate(360deg);
  }
}

.spinner {
  width: 56px;
  height: 56px;
  display: grid;
  border: 4.5px solid #0000;
  border-radius: 50%;
  border-color: #dbdcef #0000;
  animation: spinner-e04l1k 1s infinite linear;
}

.spinner::before,
.spinner::after {
  content: "";
  grid-area: 1/1;
  margin: 2.2px;
  border: inherit;
  border-radius: 50%;
}

.spinner::before {
  border-color: #474bff #0000;
  animation: inherit;
  animation-duration: 0.5s;
  animation-direction: reverse;
}

.spinner::after {
  margin: 8.9px;
}

@keyframes spinner-e04l1k {
  100% {
    transform: rotate(1turn);
  }
}

.spinner {
  position: relative;
  width: 33.6px;
  height: 33.6px;
  perspective: 67.2px;
}

.spinner div {
  width: 100%;
  height: 100%;
  background: #474bff;
  position: absolute;
  left: 50%;
  transform-origin: left;
  animation: spinner-16s03x 2s infinite;
}

.spinner div:nth-child(1) {
  animation-delay: 0.15s;
}

.spinner div:nth-child(2) {
  animation-delay: 0.3s;
}

.spinner div:nth-child(3) {
  animation-delay: 0.45s;
}

.spinner div:nth-child(4) {
  animation-delay: 0.6s;
}

.spinner div:nth-child(5) {
  animation-delay: 0.75s;
}

@keyframes spinner-16s03x {
  0% {
    transform: rotateY(0deg);
  }

  50%, 80% {
    transform: rotateY(-180deg);
  }

  90%, 100% {
    opacity: 0;
    transform: rotateY(-180deg);
  }
}

.spinner {
  position: absolute;
  width: 9px;
  height: 9px;
}

.spinner div {
  position: absolute;
  width: 50%;
  height: 150%;
  background: #474bff;
  transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1%));
  animation: spinner-fzua35 1s calc(var(--delay) * 1s) infinite ease;
}

.spinner div:nth-child(1) {
  --delay: 0.1;
  --rotation: 36;
  --translation: 150;
}

.spinner div:nth-child(2) {
  --delay: 0.2;
  --rotation: 72;
  --translation: 150;
}

.spinner div:nth-child(3) {
  --delay: 0.3;
  --rotation: 108;
  --translation: 150;
}

.spinner div:nth-child(4) {
  --delay: 0.4;
  --rotation: 144;
  --translation: 150;
}

.spinner div:nth-child(5) {
  --delay: 0.5;
  --rotation: 180;
  --translation: 150;
}

.spinner div:nth-child(6) {
  --delay: 0.6;
  --rotation: 216;
  --translation: 150;
}

.spinner div:nth-child(7) {
  --delay: 0.7;
  --rotation: 252;
  --translation: 150;
}

.spinner div:nth-child(8) {
  --delay: 0.8;
  --rotation: 288;
  --translation: 150;
}

.spinner div:nth-child(9) {
  --delay: 0.9;
  --rotation: 324;
  --translation: 150;
}

.spinner div:nth-child(10) {
  --delay: 1;
  --rotation: 360;
  --translation: 150;
}

@keyframes spinner-fzua35 {
  0%, 10%, 20%, 30%, 50%, 60%, 70%, 80%, 90%, 100% {
    transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1%));
  }

  50% {
    transform: rotate(calc(var(--rotation) * 1deg)) translate(0, calc(var(--translation) * 1.5%));
  }
}

.spinner {
  --d: 24.6px;
  width: 4.5px;
  height: 4.5px;
  border-radius: 50%;
  color: #474bff;
  box-shadow: calc(1*var(--d))      calc(0*var(--d))     0 0,
          calc(0.707*var(--d))  calc(0.707*var(--d)) 0 1.1px,
          calc(0*var(--d))      calc(1*var(--d))     0 2.2px,
          calc(-0.707*var(--d)) calc(0.707*var(--d)) 0 3.4px,
          calc(-1*var(--d))     calc(0*var(--d))     0 4.5px,
          calc(-0.707*var(--d)) calc(-0.707*var(--d))0 5.6px,
          calc(0*var(--d))      calc(-1*var(--d))    0 6.7px;
  animation: spinner-a90wxe 1s infinite steps(8);
}

@keyframes spinner-a90wxe {
  100% {
    transform: rotate(1turn);
  }
}

.loader {
  --dim: 3rem;
  width: var(--dim);
  height: var(--dim);
  position: relative;
  animation: spin988 2s linear infinite;
}

.loader .circle {
  --color: #333;
  --dim: 1.2rem;
  width: var(--dim);
  height: var(--dim);
  background-color: var(--color);
  border-radius: 50%;
  position: absolute;
}

.loader .circle:nth-child(1) {
  top: 0;
  left: 0;
}

.loader .circle:nth-child(2) {
  top: 0;
  right: 0;
}

.loader .circle:nth-child(3) {
  bottom: 0;
  left: 0;
}

.loader .circle:nth-child(4) {
  bottom: 0;
  right: 0;
}

@keyframes spin988 {
  0% {
    transform: scale(1) rotate(0);
  }

  20%, 25% {
    transform: scale(1.3) rotate(90deg);
  }

  45%, 50% {
    transform: scale(1) rotate(180deg);
  }

  70%, 75% {
    transform: scale(1.3) rotate(270deg);
  }

  95%, 100% {
    transform: scale(1) rotate(360deg);
  }
}

.loader {
  --dim: 5rem;
  width: var(--dim);
  height: var(--dim);
  border: 7px solid #2596be;
  border-top-color: transparent;
  border-bottom-color: transparent;
  border-radius: 50%;
  animation: spin_51 1.5s infinite linear;
}

@keyframes spin_51 {
  from {
    transform: rotate(0)
  }

  to {
    transform: rotate(360deg)
  }
}

.loader {
  --dim: 6rem;
  background-color: #ED8A19;
  width: var(--dim);
  height: var(--dim);
  border-radius: 50%;
  display: grid;
  place-items: center;
  animation: spin_412 5s infinite;
}

.loader .loader-svg {
  transform: translateY(-2px) scale(.7);
}

@keyframes spin_412 {
  0% {
    transform: rotate(0) scale(1);
  }

  50% {
    transform: rotate(720deg) scale(1.3);
  }

  100% {
    transform: rotate(0) scale(1);
  }
}
